/**
 * Notification adapter interface — defines the contract for delivering notifications.
 *
 * Adapters handle the actual delivery mechanism (email, webhook, etc.)
 * while the NotificationService handles routing and formatting.
 */

export interface NotificationPayload {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export interface NotificationAdapter {
  readonly name: string;
  send(payload: NotificationPayload): Promise<void>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * In this demo, "sending" means storing the email in an in-memory log.
 * A real implementation would use an SMTP client or email API.
 */

import type { NotificationAdapter, NotificationPayload } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly name = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  async send(payload: NotificationPayload): Promise<void> {
    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: payload.sentAt,
    };
    this.sentEmails.push(email);
    this.logger.info(`Email sent to ${payload.recipient}: ${payload.subject}`);
  }

  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Webhook notification adapter — delivers notifications by POSTing JSON to a URL.
 *
 * Formats the notification payload as JSON and sends it via HTTP POST.
 * In this demo, "sending" means storing the delivery record in-memory
 * and invoking a configurable sender function (defaults to global fetch).
 */

import type { NotificationAdapter, NotificationPayload } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface WebhookDelivery {
  url: string;
  payload: WebhookPayloadBody;
  deliveredAt: Date;
  success: boolean;
  statusCode?: number;
}

export interface WebhookPayloadBody {
  notificationId: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: string;
}

export type HttpPostFn = (url: string, options: {
  method: string;
  headers: Record<string, string>;
  body: string;
}) => Promise<{ ok: boolean; status: number }>;

export class WebhookAdapter implements NotificationAdapter {
  readonly name = 'webhook';
  private logger = new Logger('WebhookAdapter');
  private deliveries: WebhookDelivery[] = [];
  private url: string;
  private httpPost: HttpPostFn;

  constructor(url: string, httpPost?: HttpPostFn) {
    this.url = url;
    this.httpPost = httpPost ?? globalThis.fetch;
  }

  async send(payload: NotificationPayload): Promise<void> {
    const webhookBody: WebhookPayloadBody = {
      notificationId: payload.id,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: payload.sentAt.toISOString(),
    };

    let success = false;
    let statusCode: number | undefined;

    try {
      const response = await this.httpPost(this.url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(webhookBody),
      });
      success = response.ok;
      statusCode = response.status;
    } catch (error) {
      this.logger.error(`Webhook delivery failed to ${this.url}: ${error}`);
    }

    this.deliveries.push({
      url: this.url,
      payload: webhookBody,
      deliveredAt: new Date(),
      success,
      statusCode,
    });

    if (success) {
      this.logger.info(`Webhook delivered to ${this.url}: ${payload.subject}`);
    } else {
      this.logger.warn(`Webhook delivery to ${this.url} failed with status ${statusCode}`);
    }
  }

  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  clearDeliveries(): void {
    this.deliveries = [];
  }

  getUrl(): string {
    return this.url;
  }
}

/**
 * Notification service — handles sending notifications in response to events.
 *
 * NOTE: This service currently uses TWO different patterns for receiving
 * notifications, which is inconsistent and should be unified:
 *
 * 1. EventBus subscriptions (event-driven) — used for order:created events
 * 2. CallbackRegistry (direct callbacks) — used for order:status-changed events
 *
 * Both approaches work but the mixed usage makes the codebase harder to
 * maintain. A future refactor should pick ONE approach and use it consistently.
 *
 * Depends on:
 * - EventBus (event system) for receiving some events
 * - CallbackRegistry (direct callbacks) for other events
 * - NotificationAdapter instances for delivery (email, webhook, etc.)
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import { statusChangeCallbacks } from '../utils/callback-registry.js';
import { Logger } from '../utils/logger.js';

export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  sentAt: Date;
}

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: NotificationAdapter[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for delivery.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.push(adapter);
    this.logger.info(`Registered notification adapter: ${adapter.name}`);
  }

  /**
   * Get all registered adapters.
   */
  getAdapters(): NotificationAdapter[] {
    return [...this.adapters];
  }

  /**
   * Register event handlers for notification triggers.
   *
   * Uses EventBus for order creation (event-driven pattern)
   * and CallbackRegistry for status changes (direct callback pattern).
   */
  private registerHandlers(): void {
    // Pattern 1: EventBus subscription for order creation
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    // Pattern 2: CallbackRegistry for status changes
    statusChangeCallbacks.register((event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private handleOrderCreated(event: OrderCreatedEvent): void {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    this.sendNotification({
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private handleOrderStatusChanged(event: OrderStatusChangedEvent): void {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    this.sendNotification({
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Send a notification — stores it in memory and dispatches to all registered adapters.
   */
  private sendNotification(params: {
    recipient: string;
    subject: string;
    body: string;
  }): void {
    const notification: Notification = {
      id: generateNotificationId(),
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      sentAt: new Date(),
    };
    this.notifications.push(notification);
    this.logger.info(`Notification sent: ${notification.id} to ${params.recipient}`);

    for (const adapter of this.adapters) {
      adapter.send(notification).catch((error) => {
        this.logger.error(`Adapter ${adapter.name} failed: ${error}`);
      });
    }
  }

  /**
   * Get all sent notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

