import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/adapters/notification.adapter.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  const samplePayload: NotificationPayload = {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed.',
    sentAt: new Date('2026-01-15T10:00:00Z'),
  };

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  it('should have name "email"', () => {
    expect(adapter.name).toBe('email');
  });

  it('should store sent email', async () => {
    await adapter.send(samplePayload);

    const emails = adapter.getSentEmails();
    expect(emails).toHaveLength(1);
    expect(emails[0]?.to).toBe('alice@example.com');
    expect(emails[0]?.subject).toBe('Order Confirmation: order-1');
    expect(emails[0]?.body).toBe('Your order has been placed.');
  });

  it('should track multiple emails', async () => {
    await adapter.send(samplePayload);
    await adapter.send({ ...samplePayload, recipient: 'bob@example.com' });

    expect(adapter.getSentEmails()).toHaveLength(2);
  });

  it('should clear sent emails', async () => {
    await adapter.send(samplePayload);
    adapter.clearSentEmails();

    expect(adapter.getSentEmails()).toHaveLength(0);
  });
});
